import sqlite3

class DocumentAccessSystem:
    def __init__(self, db_name='document_access.db'):
        self.db_name = db_name
        self._init_db()

    def _init_db(self):
        conn = sqlite3.connect(self.db_name)
        cursor = conn.cursor()
        cursor.execute('''
            CREATE TABLE IF NOT EXISTS permissions (
                user_id TEXT NOT NULL,
                file_path TEXT NOT NULL,
                access_level TEXT NOT NULL, -- e.g., 'read', 'write', 'admin'
                PRIMARY KEY (user_id, file_path)
            )
        ''')
        conn.commit()
        conn.close()

    def grant_permission(self, user_id, file_path, access_level='read'):
        conn = sqlite3.connect(self.db_name)
        cursor = conn.cursor()
        try:
            cursor.execute('''
                INSERT INTO permissions (user_id, file_path, access_level)
                VALUES (?, ?, ?)
            ''', (user_id, file_path, access_level))
            conn.commit()
        except sqlite3.IntegrityError:
            # If permission already exists, update it
            cursor.execute('''
                UPDATE permissions
                SET access_level = ?
                WHERE user_id = ? AND file_path = ?
            ''', (access_level, user_id, file_path))
            conn.commit()
        finally:
            conn.close()

    def revoke_permission(self, user_id, file_path):
        conn = sqlite3.connect(self.db_name)
        cursor = conn.cursor()
        cursor.execute('''
            DELETE FROM permissions
            WHERE user_id = ? AND file_path = ?
        ''', (user_id, file_path))
        conn.commit()
        conn.close()

    def _check_permission(self, user_id, file_path, required_level='read'):
        conn = sqlite3.connect(self.db_name)
        cursor = conn.cursor()
        cursor.execute('''
            SELECT access_level FROM permissions
            WHERE user_id = ? AND file_path = ?
        ''', (user_id, file_path))
        result = cursor.fetchone()
        conn.close()

        if result:
            user_access_level = result[0]
            # Simple check: 'read' access is sufficient for 'read' requirement
            # More complex logic could be added for 'write', 'admin' etc.
            if required_level == 'read' and user_access_level in ['read', 'write', 'admin']:
                return True
            # Add more complex access level hierarchy if needed
            # elif required_level == 'write' and user_access_level in ['write', 'admin']:
            #     return True
            return False
        return False

    def read_document(self, user_id, file_path):
        if not self._check_permission(user_id, file_path, required_level='read'):
            raise PermissionError(f"User '{user_id}' does not have permission to read '{file_path}'.")

        try:
            with open(file_path, 'r', encoding='utf-8') as f:
                content = f.read()
            return content
        except FileNotFoundError:
            raise FileNotFoundError(f"Document '{file_path}' not found.")
        except Exception as e:
            raise IOError(f"Error reading document '{file_path}': {e}")

